import 'package:dio/dio.dart';
class AppError implements Exception{AppError(this.message,{this.code,this.statusCode,this.requestId});final String message;final String? code;final int? statusCode;final String? requestId;factory AppError.fromDio(DioException e){final rid=e.response?.headers.value('X-Request-Id');if(e.type==DioExceptionType.connectionTimeout||e.type==DioExceptionType.receiveTimeout||e.type==DioExceptionType.sendTimeout)return AppError('Сервер не отвечает. Попробуйте позже.',requestId:rid);if(e.type==DioExceptionType.connectionError)return AppError('Нет соединения с сервером.',requestId:rid);final data=e.response?.data;String? code;String? msg;if(data is Map){code=data['code']?.toString();msg=data['message']?.toString();}return AppError(_message(e.response?.statusCode,code,msg),code:code,statusCode:e.response?.statusCode,requestId:rid);}static String _messageForTest(int? s,String? c,String? m)=>_message(s,c,m);static String _message(int? s,String? c,String? m){if(c=='NICKNAME_ALREADY_EXISTS')return 'Такой ник уже занят.';if(c=='VALIDATION_ERROR')return 'Проверьте введённые данные.';if(s==404)return 'Данные не найдены.';if(s==409)return m??'Конфликт данных.';if(s==413)return 'Файл слишком большой.';if(s==415)return 'Неподдерживаемый тип файла.';if(s==500)return 'Ошибка сервера.';if(s==503)return 'Сервис временно недоступен.';return m??'Не удалось выполнить запрос.';}@override String toString()=>message;}
